-- NEW ROW (not seeded by 12-01) — INSERT WHERE NOT EXISTS
INSERT INTO agent_fuel_documents (fuel_type, status, content, created_at, updated_at)
SELECT
    'pairing_fuel',
    'draft',
    '{"fuel_type":"combination","template_version":"1.0","pair_key":"juvederm_vollure_xc__sculptra_aesthetic","patient_facing_name":"Rebuild & Refine (NLF)","one_line_positioning":"Sculptra builds collagen support in the midface over months while Vollure provides precise nasolabial fold correction — address the cause and the visible crease.","package_goal":"Stimulate collagen support and directly correct nasolabial fold lines","ideal_candidate":"Adult patients with nasolabial folds who want both gradual structural collagen support (Sculptra) and immediate fold correction (Vollure). Patients willing to commit to sequential staging — Sculptra series first, then filler refinement.","not_ideal_candidate":"Patients seeking only immediate results, patients who cannot commit to a Sculptra series (2-3 sessions), patients hypersensitive to poly-L-lactic acid or HA components.","concern_tags":["Nasolabial Folds","Volume Loss","Collagen Loss","Midface Aging","Structural Support"],"why_together":"Sculptra addresses the underlying collagen loss that causes nasolabial folds to deepen; Vollure provides immediate correction of the fold crease itself. One addresses the cause, the other addresses the visible result — different depths, different mechanisms, different timelines.","A_solves":"Sculptra stimulates collagen production in the midface gradually over months — addressing the structural support loss that allows nasolabial folds to deepen.","A_does_not_solve":"Sculptra cannot provide immediate visible fold correction — results develop over months, not immediately.","B_adds":"Vollure provides immediate correction of nasolabial fold lines and moderate facial wrinkles through HA gel scaffold — addressing the visible crease that Sculptra improves only gradually.","clinical_rationale":"Sculptra stimulates collagen production in the midface; Vollure corrects nasolabial folds (NLFs) with immediate HA gel. These are different products working at different tissue depths for different purposes. Sculptra provides gradual structural support through collagen stimulation, while Vollure directly smooths the NLF crease. By establishing Sculptra collagen stimulation first, nasolabial folds may partially improve before Vollure is applied, potentially meaning less filler is needed for the final smoothing step. Note: No published controlled trial data exists for this specific combination. The FDA Sculptra label states that safety and effectiveness in combination with other products have not been evaluated in controlled clinical trials.","patient_education_summary":"The lines that run from your nose to your mouth — nasolabial folds — often deepen because the midface above them loses structural support over time. Sculptra works gradually to support collagen production in the midface, which may help lift those folds from above. Vollure is a filler designed specifically for smoothing those fold lines, and it lasts about 18 months. Your provider may suggest building the collagen support with Sculptra first — you may find the folds improve just from that. Then if there''s still a crease that concerns you, Vollure can smooth it out. This combination is used in clinical practice, but it has not been evaluated in controlled clinical trials. Your provider can discuss whether this approach makes sense for your individual situation.","staff_close":"For patients concerned about nasolabial folds, explain the upstream cause: ''Those fold lines often deepen because the midface above them is losing volume and structure. If we only fill the fold itself, we''re treating the symptom. Sculptra supports collagen production in the midface — that''s addressing the cause. Vollure then smooths whatever fold remains after that collagen support develops.''","staff_talking_points":"This combination is used in clinical practice but has not been evaluated in controlled trials. When staging sequentially, patients may need less Vollure than if filler were used alone — this is worth communicating as a potential efficiency benefit. Vollure is Allergan, Sculptra is Galderma — this is a clinical pairing based on what each product does, not a brand bundle. Present as an option the provider may recommend based on individual needs.","do_not_say":{"universal":["Unsupported clinical claims (e.g., ''clinically proven to reverse aging'')","Guarantees (e.g., ''I guarantee you''ll love the results'')","''You need this'' pressure (e.g., ''You really need both'')","Fear-based selling (e.g., ''Without this, your skin will only get worse'')","Competitor disparagement","''Liquid facelift'' overclaims","''No downtime'' when downtime exists","Permanent result claims","Off-label combination approval claims","''No risk'' statements","Price/value claims practices may not honor","Before/after exaggerations (e.g., ''20 years younger'')"],"pair_specific":["Do not promise that Sculptra will eliminate the need for Vollure — some patients will still need filler correction after Sculptra.","Do not describe Sculptra results as immediate — results develop over months.","Do not state the combination is FDA approved as a package — FDA Sculptra label notes combination use not evaluated in controlled trials.","Do not describe Sculptra as a ''filler'' — it is a biostimulator that stimulates collagen."],"practice_specific":[]},"top_objections":[{"objection_type":"timeline","patient_says":"I want my folds fixed now — why do I need to wait for Sculptra first?","handling_language":"You don''t have to wait — Vollure can address the fold immediately. The reason some providers suggest Sculptra first is that it may improve the folds from the inside out, which could mean you need less filler to get the result you want. But this is your decision to make with your provider — immediate Vollure correction is a completely valid approach.","do_not_say_in_response":"Don''t be rigid about the staging sequence. Let the provider guide individual planning."},{"objection_type":"cost","patient_says":"This sounds like a lot of product. Can I just do the filler?","handling_language":"Absolutely. Vollure can address the nasolabial folds on its own — it''s designed for exactly that. Sculptra is an additional option some providers consider for structural support. Whether adding Sculptra makes sense depends on your individual goals and what your provider recommends.","do_not_say_in_response":"Don''t push the combination if the patient prefers filler alone."},{"objection_type":"safety_concern","patient_says":"Is it safe to mix these?","handling_language":"This combination is used in clinical practice. The FDA Sculptra label notes that combination use with other products hasn''t been formally evaluated in controlled trials — your provider assesses whether it''s appropriate for your individual situation.","do_not_say_in_response":"Don''t dismiss the FDA caveat."},{"objection_type":"sculptra_timeline","patient_says":"How long does Sculptra take to work?","handling_language":"Sculptra works gradually — most patients complete 2-3 sessions spaced 4-6 weeks apart and notice changes over the following months as their own collagen production is stimulated. It''s not an immediate result — it builds over time. Vollure, in contrast, provides immediate correction at the treatment visit.","do_not_say_in_response":"Don''t overstate Sculptra timeline. It is genuinely gradual."},{"objection_type":"I_will_think_about_it","patient_says":"Let me think about Sculptra and just do filler for now.","handling_language":"That makes sense. Vollure today is a complete treatment for the nasolabial folds. We can discuss Sculptra at any future visit if you want to explore the structural support approach.","do_not_say_in_response":"Don''t push Sculptra after the patient asks to pause."}],"sequencing_note":"Sequential staging preferred: Sculptra series first (2-3 sessions, 4-6 weeks apart), then assess nasolabial folds 4-6 weeks after last Sculptra session. Same-session treatment in different tissue planes is performed by some experienced injectors but has not been evaluated in controlled trials.","timing_note":"Sculptra series first, then Vollure refinement 4-6 weeks after last session. Vollure ~18-month duration; Sculptra collagen effect 2+ years. Both have extended timelines — maintenance schedules align.","downtime_note":"Vollure: immediate volume, possible minor swelling/bruising at injection sites. Sculptra: injection site swelling and bruising possible; 5-5-5 massage protocol required post-treatment. Sculptra results build over months.","same_session_ok":"conditional — same-session in different tissue planes by experienced injectors; FDA Sculptra label notes combination use not evaluated in controlled clinical trials; provider should discuss caveat","maintenance_story":"Vollure every 12-18 months; Sculptra collagen series 2-3 sessions then annual maintenance. The extended duration of both reduces total visit count for patients committed to the approach.","rebooking_trigger":"At your Vollure follow-up, we can assess how the folds look and discuss whether adding Sculptra makes sense for structural support.","next_visit_prompt":"If structural collagen support becomes a goal at any point, we can discuss Sculptra at a future visit.","source_support_summary":"FDA Sculptra Aesthetic labeling: ''The safety and effectiveness of SCULPTRA Aesthetic used in combination with other products and procedures have not been evaluated in controlled clinical trials.'' FDA label — Juvederm Vollure XC: indicated for moderate to severe facial wrinkles and folds including nasolabial folds in adults over 21; 18-month duration. Expert consensus: supports biostimulator + HA filler combinations based on orthogonal mechanisms (PLLA collagen stimulation vs HA gel correction at different tissue depths).","evidence_level":"weak","review_status":"draft","audience":["agent","staff"],"patient_safe":false,"last_reviewed":null,"reviewed_by":null}'::jsonb,
    NOW(),
    NOW()
WHERE NOT EXISTS (
    SELECT 1 FROM agent_fuel_documents
    WHERE fuel_type = 'pairing_fuel'
      AND content->>'pair_key' = 'juvederm_vollure_xc__sculptra_aesthetic'
