-- Review status: PENDING
-- Tier: combination | Evidence: moderate
UPDATE agent_fuel_documents
SET
    content = '{"fuel_type":"combination","template_version":"1.0","pair_key":"dysport__rha_redensity","patient_facing_name":"Broad Smooth & Soften (Perioral)","one_line_positioning":"Dysport''s broad-coverage neuromodulation addresses large upper-face zones while RHA Redensity refines the perioral fine lines that neurotoxin is not suited to treat.","package_goal":"Reduce dynamic wrinkles across broad facial zones and refine perioral fine lines","ideal_candidate":"Adult patients with upper-face dynamic wrinkles (especially forehead and crow''s feet) and perioral fine lines in two distinct zones requiring different approaches.","not_ideal_candidate":"Patients with only one zone of concern, or patients hypersensitive to botulinum toxin or HA components.","concern_tags":["Dynamic Wrinkles","Perioral Lines","Crow''s Feet","Lip Lines","Fine Lines"],"why_together":"Dysport addresses upper-face movement-caused lines through neuromodulation with broader diffusion; RHA Redensity uses resilient HA technology specifically designed for perioral fine lines and dynamic areas around the mouth where neurotoxin treatment is not appropriate.","A_solves":"Dysport relaxes the muscles causing dynamic expression lines in broad upper-face zones (forehead, crow''s feet) with faster onset at 2-5 days.","A_does_not_solve":"Dysport cannot address perioral fine lines in the high-mobility zone around the mouth.","B_adds":"RHA Redensity uses resilient HA designed for the perioral zone''s constant movement, refining fine lines around the lips that neurotoxin cannot safely treat.","clinical_rationale":"Dysport''s broader diffusion treats large dynamic zones (forehead, crow''s feet) with fewer injection points and faster onset (2-5 days), while RHA Redensity uses resilient HA technology specifically designed for perioral fine lines and dynamic areas around the mouth. RHA Redensity is a finishing filler — it refines fine lines in areas that move constantly (lips, perioral region) where traditional fillers may not perform as well. This is a cross-ecosystem pairing (Galderma neurotoxin + Revance filler), which is clinically sound but may not align with single-brand loyalty programs. Category-level evidence supports BoNT-A + HA filler combinations (DOI 10.1097/DSS.0000000000000754). Dysport maintenance: every 3-4 months. RHA Redensity maintenance: varies by area treated.","patient_education_summary":"Dysport works by relaxing the muscles that cause expression lines — it''s particularly effective for broad areas like the forehead and around the eyes, and you may notice improvement within a few days. But those fine lines around your mouth are different — they''re caused by years of movement in an area that''s always active — talking, eating, smiling. RHA Redensity is a specialized filler designed for exactly those delicate perioral lines. It uses a resilient formula that moves naturally with your facial expressions rather than stiffening the area. These are two different concerns in two different parts of the face, each requiring its own approach.","staff_close":"When a patient is concerned about both forehead lines and fine lines around the mouth: ''The forehead and crow''s feet lines are from muscle movement — Dysport relaxes those muscles and works well across broad areas. The fine lines around your mouth are a different challenge. That area moves constantly, so it needs a filler that can flex with your expressions. RHA Redensity is designed specifically for those perioral lines.''","staff_talking_points":"One thing to be aware of: Dysport is a Galderma product and RHA Redensity is a Revance product, so they don''t share a loyalty program. If that matters to the patient, mention it. But the clinical rationale stands regardless of brand — each product is the best fit for its specific zone. Focus on what each product does well for the specific concern.","do_not_say":{"universal":["Unsupported clinical claims (e.g., ''clinically proven to reverse aging'')","Guarantees (e.g., ''I guarantee you''ll love the results'')","''You need this'' pressure (e.g., ''You really need both'')","Fear-based selling (e.g., ''Without this, your skin will only get worse'')","Competitor disparagement","''Liquid facelift'' overclaims","''No downtime'' when downtime exists","Permanent result claims","Off-label combination approval claims","''No risk'' statements","Price/value claims practices may not honor","Before/after exaggerations (e.g., ''20 years younger'')"],"pair_specific":["Do not suggest Dysport or any neurotoxin for the perioral area — it can impair lip and mouth function.","Do not imply RHA Redensity adds volume to the lips — it treats perioral rhytids, not lip augmentation.","Do not present the cross-ecosystem nature as a disadvantage — it is clinically irrelevant.","Do not overstate perioral maintenance duration — RHA Redensity may require more frequent retreatment than other zones."],"practice_specific":[]},"top_objections":[{"objection_type":"cost","patient_says":"Can I just do Dysport and come back for the perioral filler later?","handling_language":"Absolutely. These address two different concerns and can be done at completely separate visits.","do_not_say_in_response":"Don''t suggest urgency."},{"objection_type":"do_I_need_both","patient_says":"Can''t Dysport treat the lines around my mouth?","handling_language":"The forehead and crow''s feet lines are caused by muscle movement — that''s exactly what Dysport addresses. But the fine lines around your mouth are in a high-mobility zone where a flexible filler that moves with your expressions is more appropriate. Using neurotoxin in the perioral area could affect normal lip and mouth function.","do_not_say_in_response":"Don''t say Dysport ''doesn''t work'' around the mouth. Clarify it''s zone-appropriate treatment."},{"objection_type":"fear_of_looking_overdone","patient_says":"I don''t want my lips to look done.","handling_language":"RHA Redensity isn''t a lip augmentation — it treats fine lines around the lips, not the lips themselves. The goal is to soften those small lines while preserving natural lip shape.","do_not_say_in_response":"Don''t dismiss the concern. Clarify the distinction clearly."},{"objection_type":"downtime","patient_says":"The area around my mouth bruises easily — what should I expect?","handling_language":"The perioral area does tend to bruise more easily for some patients. If you have something coming up, scheduling Dysport today and the perioral filler after the event is a practical approach.","do_not_say_in_response":"Don''t say ''no bruising.'' Don''t minimize the concern."},{"objection_type":"I_will_think_about_it","patient_says":"Let me think about the perioral filler.","handling_language":"No rush. We can do Dysport today and keep the RHA Redensity conversation open for whenever you''re ready.","do_not_say_in_response":"Don''t push. Don''t reopen the conversation."}],"sequencing_note":"Neurotoxin administered first in same-session protocols. If sequential: Dysport 2 weeks before RHA Redensity. RHA Redensity is typically a finishing step after any structural fillers.","timing_note":"Same session or sequential visits. If sequential: 2-week interval recommended. Dysport every 3-4 months; RHA Redensity perioral every 6-12 months.","downtime_note":"Dysport: effect visible within 2-5 days, minimal visible downtime. RHA Redensity perioral: possible bruising and swelling; perioral area is particularly prone to bruising.","same_session_ok":true,"maintenance_story":"Dysport every 3-4 months; RHA Redensity perioral every 6-12 months (higher mobility area requires more frequent retreatment). Different loyalty programs — Galderma (Dysport) and Revance (RHA Redensity).","rebooking_trigger":"At your Dysport follow-up, if the perioral lines are still a concern, that''s a natural time to discuss RHA Redensity.","next_visit_prompt":"If perioral fine lines remain a concern after your Dysport results settle, we can discuss RHA Redensity at your next visit.","source_support_summary":"PubMed DOI 10.1097/DSS.0000000000000754: BoNT-A and HA fillers may be performed together in either sequence; combination superior to either alone. Category-level evidence extrapolated to this cross-ecosystem pair. FDA label — Dysport: indicated for moderate to severe glabellar lines; broader diffusion, faster onset 2-5 days. FDA label — RHA Redensity: indicated for perioral area (superficial to mid dermis) for correction of dynamic perioral rhytids in adults over 22; resilient HA for dynamic facial areas. Accepted clinical practice: zone-based complementarity (upper-face neurotoxin + perioral filler) is standard in comprehensive facial rejuvenation.","evidence_level":"moderate","review_status":"draft","audience":["agent","staff"],"patient_safe":false,"last_reviewed":null,"reviewed_by":null}'::jsonb,
    status  = 'draft'
WHERE fuel_type = 'pairing_fuel'
  AND content->>'pair_key' = 'dysport__rha_redensity';

