INSERT INTO agent_fuel_documents (fuel_type, status, content, created_at, updated_at)
SELECT
    'pairing_fuel',
    'draft',
    '{"fuel_type":"combination","template_version":"1.0","pair_key":"jeuveau__juvederm_voluma_xc","product_a":"Jeuveau","product_b":"Juvederm Voluma XC","patient_facing_name":"Relax & Restore","one_line_positioning":"Jeuveau relaxes expression lines while Voluma rebuilds the cheek structure that supports the entire face.","package_goal":"Treat dynamic wrinkles and cheek volume loss together","ideal_candidate":"Patient experiencing both upper-face expression lines and midface volume loss with cheek flattening; patient interested in a comprehensive maintenance plan addressing distinct aging concerns.","not_ideal_candidate":"Patient with single isolated concern (wrinkles only or volume only); patients with neurotoxin or HA contraindications; highly active patients should have realistic Voluma duration expectations.","concern_tags":["dynamic wrinkles","frown lines","crow''s feet","cheek volume loss","midface aging","facial aging"],"why_together":"Jeuveau relaxes muscles that create expression lines; Voluma restores deep structural cheek volume lost to aging. Neuromodulation cannot restore volume, and structural filler cannot relax muscles — these are complementary tools for different aging mechanisms.","A_solves":"Relaxes muscles causing dynamic expression lines (frown lines, crow''s feet, forehead lines)","A_does_not_solve":"Cannot restore lost structural cheek volume","B_adds":"Restores deep cheek volume through HA gel scaffold (VYCROSS technology), immediately improving midface contour and support","clinical_rationale":"Jeuveau (prabotulinumtoxinA-xvfs) is an aesthetics-only neurotoxin with Hi-Pure technology, addressing dynamic wrinkles through the standard BoNT-A mechanism. Voluma provides deep structural volume restoration in the cheeks using VYCROSS technology with up to 2-year duration. Voluma is a structural filler typically placed first in multi-filler protocols as the foundational scaffold. The combination treats expression lines (Jeuveau) alongside structural cheek volume loss (Voluma). Jeuveau has limited product-specific published evidence — the neurotoxin + filler complementarity is well-established at the category level. Patients who are highly active may metabolize Voluma faster. Jeuveau maintenance: every 3-4 months. Voluma maintenance: every 18-24 months.","patient_education_summary":"Jeuveau is a wrinkle relaxer made specifically for cosmetic use — it relaxes the muscles that create expression lines like frown lines and crow''s feet. But expression lines and cheek volume loss are two separate things. If you''re noticing your cheeks look flatter or less defined, that''s structural volume loss that happens naturally with aging — Jeuveau can''t address that. Voluma is a structural filler placed deep in the cheeks to restore that foundation, and it''s one of the longer-lasting fillers, often holding for up to two years. Treating both concerns addresses the full picture rather than just one aspect.","staff_close":"Help patients separate the concerns: expression lines are from muscle movement (Jeuveau), cheek flatness is structural volume loss (Voluma) — two different processes requiring two different solutions.","staff_talking_points":"When a patient mentions looking tired or ''deflated,'' help them separate the concerns: ''The lines on your forehead and around your eyes are from muscle movement — Jeuveau is designed to relax those muscles. But the flatness in your cheeks is structural volume loss, which is a different process entirely. Voluma is placed deep in the cheek to rebuild that structure — think of it as restoring the foundation.'' On Jeuveau: it''s sometimes called Newtox and it''s made by Evolus specifically for cosmetic use. If patients ask how it differs from other neurotoxins, be straightforward that it works through the same mechanism and the provider can discuss the options. For highly active patients: set realistic expectations about Voluma duration, as it may metabolize faster. Jeuveau is Evolus and Voluma is Allergan — different loyalty programs.","do_not_say":{"universal":["You need this","Everyone is doing this","This will make you look younger","Guaranteed results","Permanent","This will fix your problem","You''ll look natural","No one will know","This is painless","Zero downtime","Liquid facelift","This is our most popular package"],"pair_specific":["Jeuveau is better than Botox","Voluma will last forever","You''ll need less product because Jeuveau is stronger","This combination will lift your whole face"],"practice_specific":[]},"top_objections":[{"objection_type":"cost","patient_says":"That''s a lot to spend at one visit.","handling_language":"These are two separate treatments for two separate concerns. If both concerns are bothering you, addressing them together often means fewer total visits than scheduling them separately. Your provider can discuss which concern to prioritize if you''d prefer to phase the approach.","do_not_say_in_response":"It''s worth every penny. You deserve to invest in yourself."},{"objection_type":"do_i_need_both","patient_says":"Do I really need both?","handling_language":"Not necessarily — that depends on which concerns are bothering you. If the expression lines are your main concern, Jeuveau alone addresses that. If you''re also noticing your cheeks look flatter than they used to, Voluma addresses that separately. Your provider can help you prioritize.","do_not_say_in_response":"Yes, you really should do both. One without the other won''t be enough."},{"objection_type":"fear_of_overdone","patient_says":"I don''t want to look overdone or fake.","handling_language":"The goal is a result that looks like you on a good day. Jeuveau relaxes specific muscles and Voluma restores volume that''s naturally decreased — neither is about adding something new, it''s about addressing what''s changed. Your provider will discuss the amount that''s right for your face.","do_not_say_in_response":"Don''t worry, no one will know. You''ll look totally natural."},{"objection_type":"ill_think_about_it","patient_says":"I want to think about it.","handling_language":"Of course. These are two separate decisions you can make independently. Would it help to take home information on each product so you can think about them separately?","do_not_say_in_response":"Pricing changes — it''s better to decide today."}],"sequencing_note":"Neurotoxin (Jeuveau) administered first, filler (Voluma) second. If sequential visits: Jeuveau 2 weeks before Voluma to assess muscle response. In multi-filler plans, Voluma as structural scaffold is placed before fillers lower in the face.","timing_note":"Same session or sequential visits. Jeuveau retreatment at 3-4 months; Voluma touch-ups at 18-24 months.","downtime_note":"Jeuveau: minimal — possible injection-site redness or bruising resolving within hours to a day. Voluma: possible swelling or bruising at injection sites, typically resolving within 1-2 weeks.","same_session_ok":true,"maintenance_story":"Jeuveau every 3-4 months (approximately 3 visits per year). Voluma every 18-24 months. Many patients schedule Voluma touch-ups at one of their annual Jeuveau appointments.","rebooking_trigger":"At your 2-week Jeuveau follow-up, we can assess muscle response and confirm results. Voluma check-in at 2 weeks. Next Jeuveau appointment in 3-4 months.","next_visit_prompt":"How are the expression lines responding? Any questions about the cheek volume? We''ll plan your next Jeuveau appointment for 3-4 months from now.","source_support_summary":"PubMed DOI 10.1097/DSS.0000000000000754: BoNT-A and HA fillers may be performed together; combination superior to either alone (category-level). FDA label — Jeuveau: prabotulinumtoxinA-xvfs, aesthetics-only indication, Hi-Pure technology. FDA label — Juvederm Voluma XC: VYCROSS crosslinking, cheek augmentation indication, up to 2-year duration. Accepted clinical practice: neurotoxin-first sequencing in same-session protocols.","evidence_level":"moderate","review_status":"pending","audience":"staff","patient_safe":true,"last_reviewed":null,"reviewed_by":null}'::jsonb,
