INSERT INTO agent_fuel_documents (fuel_type, status, content, created_at, updated_at)
SELECT
    'pairing_fuel',
    'draft',
    '{"fuel_type":"combination","template_version":"1.0","pair_key":"sculptra_aesthetic__inmode_morpheus8","product_a":"Sculptra Aesthetic","product_b":"InMode Morpheus8","patient_facing_name":"Rebuild & Refirm","one_line_positioning":"Sculptra supports collagen production from within while Morpheus8 RF microneedling improves skin texture and firmness from a different pathway — two complementary collagen stimulation mechanisms.","package_goal":"Support collagen production and improve skin quality through dual pathways","ideal_candidate":"Patient with both volume loss and skin quality concerns (laxity, texture) who prefers a gradual, less-volume-focused approach to restoration; patient with longer-term aesthetic goals seeking comprehensive collagen support from multiple pathways.","not_ideal_candidate":"Patients with active skin infection at treatment site; patients with pacemakers or metal implants in treatment area (RF device contraindication); patients seeking immediate volume correction; patients who prefer not to engage in combination treatments without controlled trial evidence.","concern_tags":["collagen loss","skin laxity","volume loss","skin texture","facial aging"],"why_together":"Sculptra stimulates collagen through PLLA particle-based biologic response; Morpheus8 stimulates collagen through controlled RF thermal energy. These represent two different pathways to collagen stimulation — biologic (Sculptra) and thermal (Morpheus8). Sculptra also provides volume restoration that Morpheus8 cannot achieve, while Morpheus8 provides skin tightening and texture improvement that Sculptra cannot achieve.","A_solves":"Gradual collagen stimulation through PLLA particles; volume restoration over months","A_does_not_solve":"Cannot provide immediate volume correction; cannot tighten existing loose skin directly","B_adds":"Immediate wound-healing collagen response from RF thermal energy; skin tightening and texture improvement that Sculptra''s biologic pathway cannot achieve","clinical_rationale":"Sculptra stimulates collagen through PLLA particles that trigger a gradual biologic response over months. Morpheus8 stimulates collagen through controlled radiofrequency thermal energy that triggers an immediate wound-healing response. These represent two different pathways to collagen stimulation — biologic (Sculptra) and thermal (Morpheus8). Sculptra also provides volume restoration that Morpheus8 cannot achieve, while Morpheus8 provides skin tightening and texture improvement that Sculptra cannot achieve. Note: No published controlled trial data exists for this specific combination. The FDA Sculptra label states that safety and effectiveness in combination with other products and procedures have not been evaluated in controlled clinical trials.","patient_education_summary":"Sculptra works beneath the surface to gradually support collagen production — it addresses the structural side. Morpheus8 uses radiofrequency energy to improve skin texture and firmness from a different angle. Your provider may suggest using both, depending on your individual concerns. This combination is used in clinical practice, but it has not been evaluated in controlled clinical trials, so your provider can discuss whether it makes sense for your situation.","staff_close":"Different pathways to collagen support — Sculptra biologic, Morpheus8 thermal. Not evaluated in controlled trials; present as a provider-guided option based on individual patient needs.","staff_talking_points":"When a patient has both volume loss and skin quality concerns, this combination may address both from different angles. ''Sculptra supports collagen production gradually over months. RF microneedling improves texture, firmness, and fine lines through controlled thermal stimulation.'' This combination is used in clinical practice but has not been evaluated in controlled trials. Present it as an option the provider may recommend based on the patient''s individual needs. Let patients know results are gradual — this is about supporting their skin''s long-term health.","do_not_say":{"universal":["You need this","Everyone is doing this","This will make you look younger","Guaranteed results","Permanent","This will fix your problem","You''ll look natural","No one will know","This is painless","Zero downtime","Liquid facelift","This is our most popular package"],"pair_specific":["This combination has been clinically proven together","Sculptra and Morpheus8 together will completely reverse your collagen loss","You''ll need fewer Sculptra sessions if you add Morpheus8","This will replace surgery"],"practice_specific":[]},"top_objections":[{"objection_type":"evidence_concern","patient_says":"Has this combination been tested or is it experimental?","handling_language":"The FDA Sculptra label notes that its use in combination with other products has not been evaluated in controlled clinical trials. This combination is used in clinical practice based on the rationale that PLLA and RF microneedling work through different mechanisms. It''s a provider-guided decision — your provider can discuss whether it''s appropriate for your individual situation.","do_not_say_in_response":"It''s totally proven. Providers have been doing this for years — it''s the same as clinical data."},{"objection_type":"do_i_need_both","patient_says":"Can''t I just do one or the other?","handling_language":"Absolutely — these address different concerns. Sculptra is primarily about supporting volume and collagen structure over time. Morpheus8 is about improving skin quality, texture, and tightening. If you have one primary concern, your provider may recommend only the relevant treatment. These work independently.","do_not_say_in_response":"You really need both to get the full effect."},{"objection_type":"downtime","patient_says":"What''s the downtime if I do both?","handling_language":"Morpheus8 has several days of social downtime — redness, swelling, pinpoint marks. Sculptra typically has mild injection-site swelling resolving within a few days. If done together, your provider will discuss the combined recovery and whether to sequence them. Some providers prefer to separate the sessions.","do_not_say_in_response":"There''s almost no downtime — you can go back to work the same day."}],"sequencing_note":"If sequential: Sculptra series first (2-3 sessions, 4-6 weeks apart) to build collagen foundation, then Morpheus8 for texture and tightening. Same-session treatment is performed by some experienced providers but has not been evaluated in controlled trials.","timing_note":"If sequential: Sculptra first, Morpheus8 after. Maintenance: Sculptra annually; Morpheus8 1-2x per year. Timelines do not align — schedule independently.","downtime_note":"Sculptra: mild injection-site swelling and bruising, typically resolving within a few days; massage protocol required. Morpheus8: several days of social downtime — redness, swelling, pinpoint bleeding marks. Patients should plan around events.","same_session_ok":true,"maintenance_story":"Sculptra: initial series of 2-3 sessions, then annual maintenance. Morpheus8: initial series of 1-3 sessions, then 1-2x per year maintenance. Timelines are independent — schedule separately.","rebooking_trigger":"Sculptra: follow-up 4-6 weeks after each session to assess collagen response. Morpheus8: check-in at 4-6 weeks post-treatment. Discuss timing of next session in each series.","next_visit_prompt":"How is the collagen support progressing? Are you noticing any changes in skin firmness or texture? We''ll plan next steps in each treatment series based on your results.","source_support_summary":"FDA Sculptra Aesthetic labeling: indicated for correction of shallow to deep nasolabial fold contour deficiencies and other facial wrinkles. Sculptra label states: ''The safety and effectiveness of SCULPTRA Aesthetic used in combination with other products and procedures have not been evaluated in controlled clinical trials.'' FDA clearance — InMode Morpheus8: 510(k)-cleared for subdermal coagulation and ablation of soft tissue via RF microneedling. Expert consensus: supports combining biostimulators with energy-based devices in clinical practice based on complementary mechanisms.","evidence_level":"weak","review_status":"pending","audience":"staff","patient_safe":true,"last_reviewed":null,"reviewed_by":null}'::jsonb,
    NOW(),
    NOW()
WHERE NOT EXISTS (
    SELECT 1 FROM agent_fuel_documents
    WHERE fuel_type = 'pairing_fuel'
      AND content->>'pair_key' = 'sculptra_aesthetic__inmode_morpheus8'
);

